import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Calendar, Trash, ArrowLeft, Tag, X
} from 'lucide-react';

// --- ESTILOS (Movidos arriba para evitar errores de definición) ---
const modalOverlay = { position: 'fixed', inset: 0, background: 'rgba(30, 41, 59, 0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000, backdropFilter: 'blur(4px)' };
const modalContent = { background: 'white', padding: '30px', borderRadius: '24px', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const closeBtn = { background: '#f1f5f9', border: 'none', borderRadius: '50%', width: '32px', height: '32px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const dropzoneStyle = { border: '2px dashed #e2e8f0', padding: '40px', borderRadius: '20px', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px', color: '#64748b' };
const btnOfertaStyle = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' };

// --- SUB-COMPONENTE: MODAL DE GALERÍA ---
const ModalGaleria = ({ onClose, cloudName, API_URL }) => {
  const [subiendo, setSubiendo] = useState(false);
  const [log, setLog] = useState([]);

  const subirAFondo = async (e) => {
    const files = Array.from(e.target.files);
    setSubiendo(true);
    for (const file of files) {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('upload_preset', "PRODUCTOS"); 
      formData.append('folder', "GALERIA_MAESTRA");
      
      try {
        const res = await axios.post(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, formData);
        const nombreLimpio = file.name.split('.')[0].replace(/[-_.]/g, ' ').toLowerCase();
        
        await axios.post(`${API_URL}/api/galeria`, {
          nombreReferencia: nombreLimpio,
          publicId: res.data.public_id,
          url: res.data.secure_url
        });
        setLog(prev => [...prev, { name: file.name, status: 'ok' }]);
      } catch (err) {
        setLog(prev => [...prev, { name: file.name, status: 'error' }]);
      }
    }
    setSubiendo(false);
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '450px'}}>
        <div style={modalHeader}>
          <h3 style={{margin:0}}>Biblioteca Maestra</h3>
          <button onClick={onClose} style={closeBtn}><X size={18} /></button>
        </div>
        <input type="file" multiple onChange={subirAFondo} id="up-gal" style={{display:'none'}} />
        <label htmlFor="up-gal" style={dropzoneStyle}>
          {subiendo ? <Loader2 className="animate-spin" /> : <Plus />}
          <span>{subiendo ? 'Subiendo...' : 'Seleccionar fotos'}</span>
        </label>
        <div style={{maxHeight:'150px', overflowY:'auto', marginTop:'15px'}}>
          {log.map((l, i) => (
            <div key={i} style={{fontSize:'0.8rem', display:'flex', justifyContent:'space-between', padding:'5px 0', borderBottom:'1px solid #f1f5f9'}}>
              {l.name.substring(0, 20)}... <span>{l.status === 'ok' ? '✅' : '❌'}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaNueva = () => ({
    id: Date.now() + Math.random(),
    producto: '',
    precioNuevo: '',
    precioViejo: '',
    stock: '',
    peso: 0,
    limitePorCliente: 3,
    categoria: 'Almacén',
    publicado: true,
    fotoSugerida: null
  });

  const [filas, setFilas] = useState([filaNueva()]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [showGaleria, setShowGaleria] = useState(false);
  const [cargando, setCargando] = useState(false);

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  useEffect(() => {
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(e => console.log(e));
  }, [showGaleria]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    
    const nuevasFilas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0] || '';
      const precio = celdas[1] || '';
      return {
        ...filaNueva(),
        id: Math.random(),
        producto: nombre,
        precioNuevo: precio,
        precioViejo: precio,
        stock: celdas[2] || 0,
        fotoSugerida: buscarMatch(nombre)
      };
    });
    setFilas(nuevasFilas);
  };

  const actualizarFila = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const n = { ...f, [campo]: valor };
        if (campo === 'producto') n.fotoSugerida = buscarMatch(valor);
        return n;
      }
      return f;
    }));
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Define las fechas.");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          peso: Number(f.peso),
          limitePorCliente: Number(f.limitePorCliente),
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          categoria: f.categoria,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Publicado!");
      setFilas([filaNueva()]);
    } catch (e) { alert("Error al guardar."); } finally { setCargando(false); }
  };

  return (
    <div style={containerStyle}>
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <button onClick={() => setShowGaleria(true)} style={btnOfertaStyle}>
          <Database size={16}/> Biblioteca Maestra
        </button>
      </div>

      <div style={headerSection}>
        <h1 style={sidebarTitle}><Tag color="#e67e22"/> Editor de Inventario</h1>
        <p style={{color: '#94a3b8'}}>Pega de Excel o escribe directamente.</p>
      </div>

      <div style={tableWrapper} onPaste={handlePaste}>
        <table style={mainTable}>
          <thead>
            <tr style={thRow}>
              <th style={thCell}>Foto</th>
              <th style={thCell}>Producto</th>
              <th style={thCell}>P. Nuevo</th>
              <th style={thCell}>P. Viejo</th>
              <th style={thCell}>Stock</th>
              <th style={thCell}>Categoría</th>
              <th style={thCell}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map((f) => (
              <tr key={f.id} style={trStyle}>
                <td style={tdCell}>
                  {f.fotoSugerida ? 
                    <img alt="Sugerencia" src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_100,c_fill/v1/${f.fotoSugerida.publicId}`} style={thumbImg} /> 
                    : <div style={noThumb}><ImageIcon size={20} color="#cbd5e1"/></div>
                  }
                </td>
                <td style={tdCell}><input style={inputTable} placeholder="Producto..." value={f.producto} onChange={e => actualizarFila(f.id, 'producto', e.target.value)} /></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioNuevo} onChange={e => actualizarFila(f.id, 'precioNuevo', e.target.value)} /></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioViejo} onChange={e => actualizarFila(f.id, 'precioViejo', e.target.value)} /></td>
                <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.stock} onChange={e => actualizarFila(f.id, 'stock', e.target.value)} /></td>
                <td style={tdCell}>
                  <select style={selectStyle} value={f.categoria} onChange={e => actualizarFila(f.id, 'categoria', e.target.value)}>
                    <option value="Almacén">Almacén</option>
                    <option value="Bebidas">Bebidas</option>
                    <option value="Limpieza">Limpieza</option>
                  </select>
                </td>
                <td style={tdCell}>
                  <button onClick={() => setFilas(filas.filter(r => r.id !== f.id))} style={btnDel}><Trash size={16}/></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <button onClick={() => setFilas([...filas, filaNueva()])} style={btnAddRow}><Plus size={18}/> Nueva Fila</button>
      </div>

      <div style={footerStyle}>
        <div style={{display:'flex', gap:'15px'}}>
          <input type="date" style={dateInput} value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} />
          <input type="date" style={dateInput} value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} />
        </div>
        <div style={{display:'flex', gap:'10px'}}>
          <button onClick={() => setFilas([filaNueva()])} style={btnLimpiar}>Limpiar</button>
          <button onClick={publicarOfertas} disabled={cargando} style={btnNuevaSucursalCustom}>
            {cargando ? <Loader2 className="animate-spin" size={18}/> : <Sparkles size={18}/>}
            Publicar
          </button>
        </div>
      </div>

      {showGaleria && <ModalGaleria cloudName={CLOUD_NAME} API_URL={API_URL} onClose={() => setShowGaleria(false)} />}
    </div>
  );
};

// --- RESTO DE ESTILOS (Al final) ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const headerSection = { marginBottom: '30px' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thRow = { background: '#f8fafc', borderBottom: '1px solid #e2e8f0' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem' };
const tdCell = { padding: '10px', borderBottom: '1px solid #f1f5f9' };
const trStyle = { transition: '0.2s' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', background: 'transparent' };
const selectStyle = { border: '1px solid #e2e8f0', padding: '8px', borderRadius: '8px', background: '#f8fafc' };
const thumbImg = { width: '50px', height: '50px', borderRadius: '8px', objectFit: 'cover' };
const noThumb = { width: '50px', height: '50px', background: '#f1f5f9', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnAddRow = { width: '100%', padding: '15px', background: 'white', border: 'none', color: '#e67e22', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' };
const footerStyle = { marginTop: '20px', padding: '20px', background: 'white', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', border: '1px solid #e2e8f0' };
const dateInput = { padding: '10px', borderRadius: '10px', border: '1px solid #e2e8f0' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const btnLimpiar = { background: '#fef2f2', color: '#ef4444', border: 'none', padding: '12px 20px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold' };
const btnDel = { color: '#cbd5e1', background: 'none', border: 'none', cursor: 'pointer' };

export default GestionOfertas;
